#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-04-28

# test-dashboard-specs.sh — smoke test for #1527 json-render dashboard emission
# Validates that explore + assess example specs pass the validator and render to markdown.

set -uo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="${CLAUDE_PROJECT_DIR:-$(cd "$SCRIPT_DIR/../.." && pwd)}"

PASS=0
FAIL=0

check() {
  local name="$1"; shift
  if "$@" >/dev/null 2>&1; then
    echo "  PASS $name"
    PASS=$((PASS + 1))
  else
    echo "  FAIL $name"
    FAIL=$((FAIL + 1))
  fi
}

check_fails() {
  local name="$1"; shift
  if ! "$@" >/dev/null 2>&1; then
    echo "  PASS $name (correctly rejected)"
    PASS=$((PASS + 1))
  else
    echo "  FAIL $name (should have rejected but didn't)"
    FAIL=$((FAIL + 1))
  fi
}

echo "Dashboard spec validator smoke tests (#1527)"
echo

for skill in explore assess; do
  spec_md="$PROJECT_ROOT/src/skills/$skill/references/dashboard-spec.md"
  spec_ex="$PROJECT_ROOT/src/skills/$skill/references/dashboard-example.json"
  script="$PROJECT_ROOT/src/skills/$skill/scripts/render-spec.mjs"

  echo "[$skill]"
  check "dashboard-spec.md exists"        test -f "$spec_md"
  check "dashboard-example.json exists"   test -f "$spec_ex"
  check "render-spec.mjs exists"          test -f "$script"
  check "render-spec.mjs is executable"   test -x "$script"
  check "example validates"               node "$script" "$spec_ex" --check
  check "example renders to markdown"     node "$script" "$spec_ex"
  echo
done

# Negative cases
echo "[invalid specs]"
TMP="$(mktemp)"
trap "rm -f $TMP" EXIT
SCRIPT="$PROJECT_ROOT/src/skills/explore/scripts/render-spec.mjs"

echo '{ "root": "x", "elements": {} }' > "$TMP"
check_fails "rejects unresolved root" node "$SCRIPT" "$TMP" --check

echo '{ "root": "x", "elements": { "x": { "type": "BarMeter", "props": { "label": "Bad", "value": 42 } } } }' > "$TMP"
check_fails "rejects out-of-range BarMeter" node "$SCRIPT" "$TMP" --check

echo '{ "root": "x", "elements": { "x": { "type": "FakeComponent", "props": {} } } }' > "$TMP"
check_fails "rejects unknown component type" node "$SCRIPT" "$TMP" --check

echo '{ "root": "x", "elements": { "x": { "type": "Card", "props": {}, "children": ["missing"] } } }' > "$TMP"
check_fails "rejects dangling child reference" node "$SCRIPT" "$TMP" --check

echo
echo "─── Results ───"
echo "  PASS: $PASS"
echo "  FAIL: $FAIL"
echo

if [[ $FAIL -gt 0 ]]; then
  exit 1
fi
exit 0
